import { StudioLayouts } from '.';
import type { StudioLayoutBasePropsConfig } from './StudioBaseSchema';
export interface StudioLayoutColorPickerConfig extends Omit<StudioLayoutBasePropsConfig, 'htmlAttrs'> {
    /**
     * Type of the layout component.
     */
    type: `${StudioLayouts.colorPicker}`;
    /**
     * Current color value.
     * @example "#ff0000"
     */
    value?: string;
    /**
     * Indicates whether the component is disabled.
     * @default false
     */
    disabled?: boolean;
    /**
     * Callback function triggered when the color value changes.
     * @examples ({ value, setState }) => setState({ value });
     */
    onChange?: '__fn__';
}
